const payload = $input.first().json;

// Extract phone number (phoneNumber takes priority over phone)
const phone = payload.phoneNumber || payload.phone || '';

// Map country from phone prefix (longest prefixes first)
const countryMap = [
  ['+971', 'Dubai'],
  ['+852', 'Hong Kong'],
  ['+65', 'Singapore'],
  ['+64', 'New Zealand'],
  ['+61', 'Australia'],
  ['+60', 'Malaysia'],
  ['+1', 'United States / Canada'],
];

let country = 'Unknown';
for (const [prefix, name] of countryMap) {
  if (phone.startsWith(prefix)) {
    country = name;
    break;
  }
}

// Format meeting start time in Singapore timezone
const eventStart = new Date(payload.eventStartTime);
const formattedTime = eventStart.toLocaleString('en-SG', {
  weekday: 'short',
  month: 'short',
  day: 'numeric',
  year: 'numeric',
  hour: 'numeric',
  minute: '2-digit',
  hour12: true,
  timeZone: 'Asia/Singapore'
});

// Ensure gmeetLink has https://
let gmeetLink = payload.gmeetLink || '';
if (gmeetLink && !gmeetLink.startsWith('http')) {
  gmeetLink = 'https://' + gmeetLink;
}

// Emoji + label per event type
const emojiMap = {
  'Meeting Scheduled': '\u2705',
  'Meeting Rescheduled': '\ud83d\udd04',
  'Meeting Cancelled': '\u274c',
};

const eventType = payload.eventType || 'Unknown Event';
const emoji = emojiMap[eventType] || '\ud83d\udcc5';
const headerText = `${emoji} ${eventType}`;

return [{
  json: {
    fullName: payload.fullName || 'N/A',
    restaurantName: payload.restaurantName || 'N/A',
    email: payload.email || 'N/A',
    phone: phone || 'N/A',
    country,
    formattedTime,
    gmeetLink: gmeetLink || 'N/A',
    salesPerson: payload.scheduledUserEmail || 'N/A',
    headerText,
    fallbackText: `${headerText} \u2014 ${payload.fullName || 'N/A'} (${payload.restaurantName || 'N/A'})`
  }
}];

